	SELECT SQ_FQC_SEQ.NEXTVAL FROM DUAL

INSERT INTO MCP_FQC_BAS (
FQC_SEQ                  --참여 일련번호
, FQC_PLCY_CD              --프리퀀시 정책 코드
, USER_ID                  --회원아이디
, BNF_CD                   --혜택코드
, FQC_DESC                 --설명
, SYS_RDATE_DD             --등록일 YYYYMMDD
, STRT_DTTM                --시작일
, END_DTTM                 --종료일
, RIP                      --등록아이피
, REGST_ID                 --등록자 ID
, REGST_DTTM               --등록일시
, RVISN_ID                 --수정자 ID
, RVISN_DTTM               --수정일시
) VALUES (
#{fqcSeq}
, #{fqcPlcyCd}
, #{userId}
, #{bnfCd}
, #{fqcDesc}
, TO_CHAR(SYSDATE, 'YYYYMMDD')
, TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')
, '99991231235959'
, #{rip}
, #{userId}
, SYSDATE
, #{userId}
, SYSDATE
)

mapper.select:
SELECT FQC_SEQ , FQC_PLCY_MSN_CD --프리퀀시 정책미션 코드 , MSN_TP_CD --미션 종류 코드 , STATE_CODE --상태값 , BYPASS_CHECK_YN --Y인 경우 검증 로직을 수행하지 않음 , CONTRACT_NUM --계약번호 , UET_SEQ --이벤트 공유 키값 , MRK_STRT_DTTM --약관동의날짜 , COMMEND_ID --추천인 아이디 , RE_CONTRACT_NUM --피추천인 계약번호 , REVIEW_ID --사용후기 일련번호 , INTERNET_ID --kt internet id , DTL_DESC , SYS_RDATE_DD , STRT_DTTM , END_DTTM FROM MCP_FQC_DLT WHERE 1=1 AND FQC_SEQ = #{fqcSeq}
AND MSN_TP_CD = #{msnTpCd}
AND END_DTTM = #{endDttm}
AND END_DTTM > TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')

