INSERT INTO MCP_FQC_DLT (
						  FQC_SEQ                  --참여 일련번호
						, FQC_PLCY_MSN_CD          --프리퀀시 정책미션 코드
						, MSN_TP_CD                --미션 종류 코드
						, STATE_CODE               --상태값
						, CONTRACT_NUM             --계약번호
						, UET_SEQ                  --이벤트 공유 키값
						, COMMEND_ID               --추천인 아이디
						, MRK_STRT_DTTM            --약관동의날짜
						, RE_CONTRACT_NUM          --피추천인 계약번호
						, REVIEW_ID                --사용후기 일련번호
						, INTERNET_ID              --kt internet id
						, DTL_DESC                 --설명
						, SYS_RDATE_DD             --등록일 YYYYMMDD
						, STRT_DTTM                --시작일
						, END_DTTM                 --종료일
						, RIP                      --등록아이피
						, REGST_ID                 --등록자 ID
						, REGST_DTTM               --등록일시
						, RVISN_ID                 --수정자 ID
						, RVISN_DTTM               --수정일시
) VALUES (
		   #{fqcSeq}
		 , #{fqcPlcyMsnCd}
		 , #{msnTpCd}
		 , #{stateCode}
		 , #{contractNum}
		 , #{uetSeq}
		 , #{commendId}
		 , #{mrkStrtDttm}
		 , #{reContractNum}
		 , #{reviewId}
		 , #{internetId}
		 , #{dtlDesc}
		 , TO_CHAR(SYSDATE, 'YYYYMMDD')
		 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')
		 , '99991231235959'
		 , #{rip}
		 , #{regstId}
		 , SYSDATE
		 , #{regstId}
		 , SYSDATE
		 )

