SELECT COUNT(*) FROM MCP_FQC_PLCY_PLA
WHERE 1=1
  AND TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN STRT_DTTM AND END_DTTM
  AND FQC_PLCY_CD = #{fqcPlcyCd}
  AND SOC_CODE = #{socCode}

SELECT FQC_PLCY_MSN_CD
FROM MCP_FQC_PLCY_MSN
WHERE 1=1
  AND FQC_PLCY_CD = #{fqcPlcyCd}
  AND MSN_TP_CD = #{msnTpCd}
